<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Http\Requests\Admin\TravelScheduleRequest; use App\Models\{SeatLayout,TravelRoute,TravelSchedule};
class TravelScheduleController extends Controller { public function index(){ $this->authorize('manage',TravelSchedule::class); return view('admin.travel-schedules.index',['schedules'=>TravelSchedule::with('route','seatLayout')->latest()->paginate(15)]); } public function create(){ $this->authorize('manage',TravelSchedule::class); return view('admin.travel-schedules.form',['schedule'=>null,'routes'=>TravelRoute::where('status','active')->get(),'layouts'=>SeatLayout::where('status','active')->get()]); } public function store(TravelScheduleRequest $r){ TravelSchedule::create($r->validated()); return redirect()->route('admin.travel-schedules.index'); } public function edit(TravelSchedule $travel_schedule){ $this->authorize('manage',TravelSchedule::class); return view('admin.travel-schedules.form',['schedule'=>$travel_schedule,'routes'=>TravelRoute::where('status','active')->get(),'layouts'=>SeatLayout::where('status','active')->get()]); } public function update(TravelScheduleRequest $r, TravelSchedule $travel_schedule){ $travel_schedule->update($r->validated()); return redirect()->route('admin.travel-schedules.index'); } public function destroy(TravelSchedule $travel_schedule){ $this->authorize('manage',TravelSchedule::class); $travel_schedule->delete(); return back(); } }
